package com.archivenexus.backend.persistence;
import com.archivenexus.backend.service.NexusStateService;import com.archivenexus.backend.task.NexusTaskEntity;import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.sql.Timestamp;import java.time.Instant;
@Service public class DomainAggregateProjectionService{
 private final JdbcTemplate jdbc;private final NexusStateService nexus;public DomainAggregateProjectionService(JdbcTemplate jdbc,NexusStateService nexus){this.jdbc=jdbc;this.nexus=nexus;}
 @Transactional public void projectManufacturing(){Instant now=Instant.now();for(var factory:nexus.factories()){String id=factory.id();long target=nexus.productionOrders().stream().filter(x->id.equals(x.factoryId())).mapToLong(x->x.targetQuantity()).sum();long produced=nexus.productionOrders().stream().filter(x->id.equals(x.factoryId())).mapToLong(x->x.producedQuantity()).sum();jdbc.update("insert into production_aggregates values (?,?,?,?,?) on conflict (aggregate_id) do update set target_quantity=excluded.target_quantity, produced_quantity=excluded.produced_quantity, projected_at=excluded.projected_at",id,id,target,produced,Timestamp.from(now));var inspections=nexus.inspections().stream().filter(x->id.equals(x.factoryId())).toList();double defect=inspections.stream().mapToDouble(x->x.defectRate()).average().orElse(0);jdbc.update("insert into inspection_aggregates values (?,?,?,?,?) on conflict (aggregate_id) do update set inspection_count=excluded.inspection_count, average_defect_rate=excluded.average_defect_rate, projected_at=excluded.projected_at",id,id,inspections.size(),defect,Timestamp.from(now));long open=nexus.maintenanceEvents().stream().filter(x->id.equals(x.factoryId())&&"OPEN".equals(x.status())).count();long critical=nexus.maintenanceEvents().stream().filter(x->id.equals(x.factoryId())&&"CRITICAL".equals(x.severity().name())).count();jdbc.update("insert into maintenance_aggregates values (?,?,?,?,?) on conflict (aggregate_id) do update set open_event_count=excluded.open_event_count, critical_event_count=excluded.critical_event_count, projected_at=excluded.projected_at",id,id,open,critical,Timestamp.from(now));}}
 @Transactional public void projectTask(NexusTaskEntity task){jdbc.update("insert into approval_aggregates values (?,?,?,?,?,?) on conflict (aggregate_id) do update set workflow_id=excluded.workflow_id, approval_id=excluded.approval_id, status=excluded.status, projected_at=excluded.projected_at",task.id(),task.id(),task.workflowId(),task.approvalId(),task.status().name(),Timestamp.from(Instant.now()));}
}
